module RefModule(
    input A,
    input B,
    input C,
    input D,
    input S0,
    input S1,
    output Y
);wire notS0, notS1;

    assign notS0 = ~S0;
    assign notS1 = ~S1;

    // Compute the output signal
  wire temp1_(A & notS1 & notS0) |
               (B & notS1 & S0) |
               (C & S1 & notS0) = (A & notS1 & notS0) |
               (B & notS1 & S0) |
               (C & S1 & notS0);
  wire temp2_(D & S1 & S0) = (D & S1 & S0);
  assign Y = temp1_(A & notS1 & notS0) |
               (B & notS1 & S0) |
               (C & S1 & notS0) | temp2_(D & S1 & S0);

endmodule
